//单个账号
//多个账号用 & 分隔
//wdxnz="authorization#androidId#oaid#mac#imei#models#channel"
//# 1 = 开启订单任务 (跑10次视频后执行1次订单)
//# 2 = 只跑订单任务 (不跑视频)
//# 0 = 关闭订单任务 (只跑视频)
//wdxnz_order="2"
//订单等级变量 (默认5)
//wdxnz_level="6"

// ===================== 内置环境变量（核心） =====================
// 直接给process.env赋值，内置wdxnz环境变量
process.env.wdxnz = 'JGezVZNtyknLFugOfbiqElASlCrNImcQ#7ade7822b2bead51#ec20fa5a2d3a958b#02:00:00:00:00:00#860661058179175#M2012K11AC#yaoqing'; // 替换为实际的变量值
process.env.wdxnz_order = '1';  //# 2 = (只跑订单)
                               // # 0 = (只跑视频)
process.env.wdxnz_level = '130';  //订单等级变量 (默认5)
// 如需内置多个变量，按此格式添加
// process.env.OTHER_VAR = '其他变量值';

// ===================== 脚本原有逻辑（示例验证） =====================
// 测试：读取并打印内置的环境变量，验证是否生效
(async () => {
    try {
        // 获取内置的wdxnz变量
        const wdxnzValue = process.env.wdxnz;
        if (wdxnzValue) {
            console.log(`内置环境变量wdxnz已生效，值为：${wdxnzValue}`);
        } else {
            console.log("环境变量wdxnz未找到");
        }
    } catch (e) {
        console.log(`读取环境变量出错：${e.message}`);
    }
})();

